const claudeItems = $input.all();
const pgItems = $('PG: Pages without description').all();
const results = [];

for (let i = 0; i < claudeItems.length; i++) {
  const resp = claudeItems[i].json;
  const pg = pgItems[i] ? pgItems[i].json : {};
  const url = pg.url || '';

  let content = '';
  try {
    content = (resp.content || [])[0]?.text || '';
    content = content.replace(/```json\n?/gi, '').replace(/```\n?/g, '').trim();
    const parsed = JSON.parse(content);
    results.push({ json: {
      url,
      description: (parsed.description || '').slice(0, 200),
      h1: (parsed.h1 || '').slice(0, 100),
      faq: JSON.stringify(parsed.faq || []),
      article: (parsed.article || '').slice(0, 2000),
      ok: true
    }});
  } catch(e) {
    results.push({ json: { url, ok: false, error: String(e) } });
  }
}
return results;

const items = $input.all();
return items.map(item => {
  const d = item.json;
  if (!d.ok) return { json: { sql: null, skipped: true, url: d.url, error: d.error } };

  const esc = s => (s || '').replace(/'/g, "''");
  const sql = `UPDATE page_seo SET description='${esc(d.description)}',h1='${esc(d.h1)}',faq='${esc(d.faq)}'::jsonb,article='${esc(d.article)}',updated_at=now() WHERE url='${esc(d.url)}' AND lang='ru'`;
  return { json: { sql, url: d.url, ok: true } };
});

const all = $input.all();
const total = all.length;
const ok = all.filter(i => !i.json.error && i.json.ok !== false).length;
const date = new Date().toISOString().slice(0,10);
return [{ json: {
  msg: '\u270d\ufe0f WF-301 SEO Content\n\n\u2705 \u041e\u0431\u043d\u043e\u0432\u043b\u0435\u043d\u043e: ' + ok + ' / ' + total + ' \u0441\u0442\u0440\u0430\u043d\u0438\u0446\n\ud83d\udcc5 ' + date
} }];
